define({"topics":[{"title":"Battery Management System","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">This application note presents an implementation of a Battery Management System (BMS) in   the Typhoon HIL environment. In the model described in this application note, the BMS logic is   implemented within the simulation using signal processing components such as the C function   component.<\/span><\/p>","href":"t-an001\/References\/battery_management_system.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e180","topics":[]},{"title":"C-HIL example-Orion Jr 2 Battery Management","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">This application note presents how an off-the-shelf Battery Management System (BMS) can be     tested in the Typhoon HIL environment. In the model described here, battery management is     implemented using the Orion Jr 2 BMS.<\/span><\/p>","href":"t-an001\/References\/orion_bms_hil.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e192","topics":[]},{"title":"BMS with FoxBMS inspired architecture","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Detailed overview of the implementation of a battery management system (BMS) with an overall architecture inspired by the foxBMS® Open-Source Platform.<\/span><\/p>","href":"t-an001\/References\/foxbms_inspired_architecture.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e204","topics":[]}]});